const body = $input.first().json.body || $input.first().json || {};
const message = body.message || body.text || '';
const ofx = body.ofx || '';
const sessionId = body.sessionId || 'sueli-default-session';
const prompt = ofx
  ? `Input do usuário: ${message}\n\nDados OFX (extrato bancário):\n${ofx}`
  : `Input do usuário: ${message}`;
return [{ json: { prompt, sessionId, message, ofx } }];

const config = $input.first().json;
const prep = $('Preparar Input').first().json;
return [{ json: { ...prep, ...config } }];

const q = (typeof query !== 'undefined' && query !== null) ? query : '';
let ofxText = '';
if (typeof q === 'string') { try { const p = JSON.parse(q); ofxText = p.ofx || p.text || q; } catch (e) { ofxText = q; } } else if (q && typeof q === 'object') { ofxText = q.ofx || q.text || ''; }
if (!ofxText || !String(ofxText).trim()) return JSON.stringify({ transacoes: [], erro: 'Nenhum texto OFX fornecido' });
const transacoes = [];
const regex = /<STMTTRN>([\s\S]*?)<\/STMTTRN>/gi;
let m;
while ((m = regex.exec(ofxText)) !== null) {
  const block = m[1];
  const get = (tag) => { const r = new RegExp('<' + tag + '>([^<]*)'); const t = block.match(r); return t ? t[1].trim() : ''; };
  const tipo = get('TRNTYPE');
  const data = get('DTPOSTED');
  const valor = get('TRNAMT');
  const memo = get('MEMO') || get('NAME');
  transacoes.push({ tipo, data, valor: parseFloat(valor) || 0, descricao: memo });
}
return JSON.stringify({ transacoes });
